/** @type {import('next').NextConfig} */
const nextConfig = {
  images: {
    domains: [
      'images.unsplash.com',
      'cdn.shopify.com', 
      'res.cloudinary.com',
      'localhost'
    ],
    formats: ['image/webp', 'image/avif'],
  },
  experimental: {
    serverActions: true,
  },
  // Remove the env section
}
```

**Environment Variables Security:**
