        </div>
        <div id="modal-root" />
        <div id="toast-root" />
      </body>
    </html>
  )
}
```

### 3. Performance Issues

**Font Loading Optimization:**
```typescript
// ❌ Current implementation could cause layout shift
const inter = Inter({
  subsets: ['latin'],
  variable: '--font-inter',
  display: 'swap', // This can cause FOIT (Flash of Invisible Text)
})
```

**Fix:**
```typescript
// ✅ Optimized font loading
const inter = Inter({
  subsets: ['latin'],
  variable: '--font-inter',
  display: 'fallback', // Better for performance
  preload: true,
})

const playfair = Playfair_Display({
  subsets: ['latin'],
  variable: '--font-playfair', 
  display: 'fallback',
  preload: true,
})
```

**Image Domain Security:**
```javascript
// ❌ Too permissive image domains
domains: [
  'images.unsplash.com',
  'cdn.shopify.com',
  'res.cloudinary.com',
  'localhost'
],
```

**Fix with more specific patterns:**
```javascript
// ✅ More secure approach
remotePatterns: [
  {
    protocol: 'https',
    hostname: 'images.unsplash.com',
    pathname: '/**',
  },
  {
    protocol: 'https', 
    hostname: 'res.cloudinary.com',
    pathname: '/your-cloud-name/**',
  },
  // Only allow localhost in development
  ...(process.env.NODE_ENV === 'development' ? [{
    protocol: 'http',
    hostname: 'localhost',
    port: '3000',
    pathname: '/**',
  }] : []),
],
```

